svg.script:

const svgNS = "http://www.w3.org/2000/svg";
const numParticles = 50;
const canvas = document.getElementById('canvas');
const pastelColors = ['#ffadad', '#ffd6a5', '#fdffb6', '#caffbf', '#9bf6ff', '#a0c4ff', '#bdb2ff', '#ffc6ff'];
const particles = [];

// Initialize particles
for (let i = 0; i < numParticles; i++) {
  const particle = document.createElementNS(svgNS, 'circle');
  const size = Math.random() * 6 + 3; // Sizes between 3 and 9
  const color = pastelColors[Math.floor(Math.random() * pastelColors.length)];
  const speedFactor = 1 / size; // Smaller particles move faster
  particle.setAttribute('cx', Math.random() * canvas.clientWidth);
  particle.setAttribute('cy', Math.random() * canvas.clientHeight);
  particle.setAttribute('r', size);
  particle.setAttribute('fill', color);
  canvas.appendChild(particle);

  particles.push({
    element: particle,
    velocity: { x: (Math.random() - 0.5) * 2 * speedFactor, y: (Math.random() - 0.5) * 2 * speedFactor },
  });
}

function updateParticles() {
  particles.forEach(p => {
    const particle = p.element;
    let x = parseFloat(particle.getAttribute('cx'));
    let y = parseFloat(particle.getAttribute('cy'));
    const { x: vx, y: vy } = p.velocity;

    // Update position
    x += vx;
    y += vy;

    // Boundary wrapping
    if (x < 0) x = canvas.clientWidth;
    if (x > canvas.clientWidth) x = 0;
    if (y < 0) y = canvas.clientHeight;
    if (y > canvas.clientHeight) y = 0;

    particle.setAttribute('cx', x);
    particle.setAttribute('cy', y);

    // Brownian update to velocity
    p.velocity.x += (Math.random() - 0.5) * 0.1;
    p.velocity.y += (Math.random() - 0.5) * 0.1;

    // Cap velocity to avoid excessive speeds
    const maxSpeed = 2 / parseFloat(particle.getAttribute('r')); // Speed inversely proportional to size
    p.velocity.x = Math.max(-maxSpeed, Math.min(maxSpeed, p.velocity.x));
    p.velocity.y = Math.max(-maxSpeed, Math.min(maxSpeed, p.velocity.y));
  });

  // Request the next frame
  requestAnimationFrame(updateParticles);
}

// Start the animation
updateParticles();
